module top_module(sck, rst, add1, init_val, cnt);parameter SIZE = 13;

   input sck;
   input rst;
   input add1;
   input [SIZE-1:0] init_val;   

   output reg [SIZE-1:0] cnt = 0;

   always @(posedge sck)
     if(rst)
       cnt = init_val;
     else
       begin
	  if(add1)
	    cnt = cnt + 1'b1;
	  else
	    cnt = cnt;
       end

endmodule
